void SetTextMode(void)

{

   if(textMode)

   {

      playStatus = 1;

      Sound_Holder.SetPlayDSoundParameters(12,-1000,0,0);

      Sound_Holder.PlayDSound(20);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

   else

   {

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(12,0,0,0);

   }

}



void Sprite_Holder.MouseClickOnDown(int spriteID)

{

   if(textMode) return;

   switch(spriteID)

   {

      case 0:

         lisc1++;

         if(lisc1>25)

            lisc1=0;

         Sprite_Holder.ChangePhase(spriteID,lisc1);

         Sound_Holder.PlayDSound(sound4);

         sound4++;

         if(sound4>18)   sound4=13;

         break;

      case 1:

         lisc2++;

         if(lisc2>17)

            lisc2=0;

         Sprite_Holder.ChangePhase(spriteID,lisc2);

         Sound_Holder.PlayDSound(sound1);

         sound1++;

         if(sound1>18)   sound1=13;

         break;

      case 2:

         lisc3++;

         if(lisc3>25)

            lisc3=0;

         Sprite_Holder.ChangePhase(spriteID,lisc3);

         Sound_Holder.PlayDSound(sound2);

         sound2++;

         if(sound2>18)   sound2=13;

         break;

      case 3:

         lisc4++;

         if(lisc4>25)

            lisc4=0;

         Sprite_Holder.ChangePhase(spriteID,lisc4);

         Sound_Holder.PlayDSound(sound3);

         sound3++;

         if(sound3>18)   sound3=13;

         break;

      case 4:

         if(zegar==0)

         {

            Sound_Holder.PlayDSound(19);

            Sprite_Holder.ChangePhase(spriteID,1);



            Sprite_Holder.ChangePhase(5,0);

            Sprite_Holder.ChangePhase(6,0);

            Sprite_Holder.ChangePhase(7,0);

            Sprite_Holder.ChangePhase(8,0);

            Sprite_Holder.ChangePhase(9,0);

            Sprite_Holder.ChangePhase(10,0);

            Sprite_Holder.ChangePhase(11,0);

            Sprite_Holder.ChangePhase(12,0);

            Sprite_Holder.ChangePhase(13,0);

            Sprite_Holder.ChangePhase(14,0);

            Sprite_Holder.ChangePhase(15,0);

            Sprite_Holder.ChangePhase(16,0);

            Sprite_Holder.ChangePhase(17,11);



            Sprite_Holder.ShowSprite(5);

            Sprite_Holder.ShowSprite(6);

            Sprite_Holder.ShowSprite(7);

            Sprite_Holder.ShowSprite(8);

            Sprite_Holder.ShowSprite(9);

            Sprite_Holder.ShowSprite(10);

            Sprite_Holder.ShowSprite(11);

            Sprite_Holder.ShowSprite(12);

            Sprite_Holder.ShowSprite(13);

            Sprite_Holder.ShowSprite(14);

            Sprite_Holder.ShowSprite(15);

            Sprite_Holder.ShowSprite(16);

            Sprite_Holder.ShowSprite(17);

            zegar=1;

            SetCursor(0);

         }

         break;   

      case 5:

      case 6:

      case 7:

      case 8:

      case 9:

      case 10:

      case 11:

      case 12:

      case 13:

      case 14:

      case 15:

      case 16:

         Sound_Holder.PlayDSound(spriteID-5);

         Sprite_Holder.ChangePhase(spriteID,1);

         Sprite_Holder.ChangePhase(17,spriteID-5);

         break;

   }

}





void Transparent_Video_Holder.MouseClickOnDown(int videoID)

{

   if(textMode) return;

   Transparent_Video_Holder.Play(videoID,0);

}





void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(textMode) return;

   if(zegar)

   {

      Sound_Holder.PlayDSound(19);

      Sprite_Holder.HideSprite(5);

      Sprite_Holder.HideSprite(6);

      Sprite_Holder.HideSprite(7);

      Sprite_Holder.HideSprite(8);

      Sprite_Holder.HideSprite(9);

      Sprite_Holder.HideSprite(10);

