      Sprite_Holder.HideSprite(12);

      Sprite_Holder.HideSprite(13);

      Sprite_Holder.HideSprite(14);

      Sprite_Holder.HideSprite(15);

      Sprite_Holder.HideSprite(16);

      Sprite_Holder.HideSprite(17);

      Sprite_Holder.ChangePhase(4,0);

      zegar=0;

   }

}





void Sound_Holder.EndPlaySound(int soundID)

{

   if(soundID==20)

   { 

      if(textMode)

      {

         playStatus=1;

         Text_Holder.EnableMouse(0);

         Text_Holder.PlaySynchroText(0);

      }

   }

   else

      Sprite_Holder.ChangePhase(soundID+5,0);

}





void Sprite_Holder.MouseMoveIn(int spriteID)

{

   if((spriteID==4 && zegar) || textMode)   return;

   SetCursor(1);

}





void Sprite_Holder.MouseMoveOut(int spriteID)

{

   if(textMode)   return;

   SetCursor(0);

}





void Transparent_Video_Holder.MouseMoveIn(int videoID)

{

   if(textMode)   return;

   SetCursor(1);

}





void Transparent_Video_Holder.MouseMoveOut(int videoID)

{

